var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제프티 바이오테크 특무함 <color=#ffd34c>코러스</color>, 대표 전용 휴게실.\\n<color=#ffd34c>윌버 웨이틀리</color> 대표, 데이트 중","JPN":"ジェフティ・バイオテック特務艦<color=#ffd34c>コーラス</color>、代表専用休憩室。\\n<color=#ffd34c>ウィルバー・ウェイトリー</color>代表、デート中","ENG":"CEO Lounge Cabin, Jehuty Biotech Special Mission Ship\xA0<color=#ffd34c>Chorus</color>\\nCEO\xA0<color=#ffd34c>Wilbur Whateley</color> on a date\xA0","TWN":"傑夫堤生物科特務艦 <color=#ffd34c>Chorus</color>。代表專用休息室。\\n<color=#ffd34c>韋爾伯·韋特利</color>代表約會中。","SCN":"杰普提生物科技特种舰<color=#ffd34c>克罗斯</color>，老板专用休息室。\\n<color=#ffd34c>韦尔伯·维特利</color>，约会中","DEU":"[[","FRA":"Vaisseau de soutien de Jehuty Biotech <color=#ffd34c>Chorus</color>, cabine du Président.\\nRencard du président <color=#ffd34c>Wilbur</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>탑승자들의 신원 조회를 마쳤습니다. 이륙 중 선체가 다소 흔들릴 수 있으니 주의해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>搭乗者の身元照会が完了しました。離陸中に船体が多少揺れることがありますので、ご注意ください。</color>","ENG":"<color=#ffd34c>Passenger identification complete. Please note the cabin may experience some turbulence during takeoff.</color>","TWN":"<color=#ffd34c>乘客資料確認完畢。請注意，升空時船身會有點晃動的情形。</color>"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"차원함선에는 이런 시설도 있구나……. 직접 타 보는 건 처음이야…….","JPN":"次元艦船にこんな施設もあるのね……乗るのは初めて……","ENG":"Wow, so they've got all this fancy stuff on a dimensional ship… I've never actually been on one before…","TWN":"次元艦船中竟然還有這種設備……我還是第一次搭呢……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하. 앞으로는 원한다면 언제든지 탈 수 있을 거야.","JPN":"ハハ。これからは君が望むならいくらでも乗れるさ。","ENG":"Haha. From now on, you'll get to ride on one whenever you wish.","TWN":"哈哈～喜歡的話，之後你隨時想搭都沒問題！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"자, 포도주야. 목도 축일 겸 한 잔 마셔.","JPN":"さあ、ワインだ。気持ちを落ち着かせるためにも一杯飲もう。","ENG":"Here's some wine. Have a glass to quench your thirst.","TWN":"來，這是葡萄酒，喝一杯潤潤喉吧！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜 그래? 아까부터 안색이 나쁜데?","JPN":"どうしたんだ？　さっきから顔色が悪いみたいだが。","ENG":"What's wrong? You've been looking distressed for a while.","TWN":"怎麼了？你從剛才臉色就怪怪的？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기네 연구소……. 폭발한 지 한참 지났는데 아직도 연기가 올라오고 있었어.","JPN":"ダーリンの研究所……爆発してから結構経ったのに未だに煙が上がってるの。","ENG":"Your lab… It's been hours since it blew up, but there's still smoke coming from it.","TWN":"親愛的研究所……已經爆炸一段時間了，怎麼都沒看到煙往上竄？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그야 그렇겠지. 이 일대에서는 제일 큰 연구 시설이었으니까.","JPN":"それはそうだろうな。この一帯では一番大きな研究施設だったから。","ENG":"Well, that's no surprise. It was the biggest research center in the area.","TWN":"喔～應該是因為那是這一帶最大的研究設施吧？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기는 분하지도 않아? 그 이상한 여자애가 폭발시킨 거라며?","JPN":"ダーリンは悔しくない？　あの変な子が爆発させたんでしょ？","ENG":"Aren't you even angry? Didn't you say that weird girl blew it up?","TWN":"親愛的你不生氣嗎？那個詭異的丫頭炸掉你的研究室欸？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"어렵게 만든 회사가 큰 손해를 보게 생겼는데……. 나만 챙겨 주고…….","JPN":"苦労して作った会社が大きな損害を受けたのに……私のことばかり気遣ってくれて……","ENG":"You've worked so hard to build this company… But you seem concerned only for me…","TWN":"你辛辛苦苦才建立起來的公司，結果遇到這麼大的虧損……你還只顧著我……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기가 걱정돼. 내가 안 보는 곳에서 많이 슬퍼할까 봐.","JPN":"ダーリンが心配なの。私の見てないところで落ち込んでるかもって。","ENG":"I'm worried about you, babe. Worried that you're really upset but trying to hide it around me.","TWN":"人家很擔心你，你不要自己眼淚往肚子裡吞。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"갑자기 이런 일에 휘말려서 정신이 없을 텐데, 넌 내 걱정부터 해 주는구나.","JPN":"急にこんなことに巻き込まれて困惑しているはずなのに、君は僕のことを心配してくれるんだね。","ENG":"It must be hectic for you to be embroiled in this mess… and yet you worry about me first.","TWN":"你突然捲進這種事應該很驚慌吧？結果你竟然先關心我。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"고마워. 네가 옆에 없었더라면 어떻게 됐을지, 상상하기도 끔찍해.","JPN":"ありがとう。君がそばにいなかったらどうなっていたのか、想像したくもない。","ENG":"Thank you, darling. I'd hate to imagine what would have happened if I didn't have you by my side.","TWN":"謝謝親愛的，我真不敢想像，萬一你不在我身邊會怎樣。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"손해가 크겠지만 뭐 어때.","JPN":"損害は大きいけど、まあいいじゃないか。","ENG":"Sure, the company may take a big hit from this, but who cares?","TWN":"這些虧損算什麼！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"나한테는 자기가 있는데.","JPN":"君が側にいてくれるならそれだけでいいさ。","ENG":"As long as I have you.","TWN":"起碼我還有你！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야. 직원 분들도 계시잖아. 이런 데서 부끄럽게 키스는…….","JPN":"ダ、ダーリン。会社の方もいらっしゃるのに、こんなところでキスするのは恥ずかしいよ……","ENG":"Aww, babe… Your employees are still here. We can't be kissing like this…","TWN":"討厭～大家都在呢～你這樣親人家，人家會害羞……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};